+fn verify_qe_identity(collateral: &Collateral) -> Result<(), Error> {
+    // Parse the QE Identity issuer certificate chain
+    let qe_identity_issuer_chain = &collateral.qe_identity_issuer_chain;
+    let certs = parse_certificate_chain(qe_identity_issuer_chain)?;
+
+    if certs.len() < 2 {
+        return Err(Error::InvalidCertificateChain(
+            "QE Identity issuer chain must contain at least 2 certificates".to_string(),
+        ));
+    }
+
+    // Verify the certificate chain (leaf -> intermediate -> root)
+    verify_certificate_chain(&certs)?;
+
+    // Verify the root certificate is a trusted Intel root CA
+    verify_intel_root_ca(&certs[certs.len() - 1])?;
+
+    // Get the signing (leaf) certificate's public key
+    let signing_cert = &certs[0];
+    let public_key = signing_cert
+        .public_key()
+        .parsed()
+        .map_err(|e| Error::CertificateParseError(format!("Failed to parse public key: {}", e)))?;
+
+    let ec_point = match public_key {
+        x509_parser::public_key::PublicKey::EC(point) => point.data(),
+        _ => {
+            return Err(Error::InvalidPublicKey(
+                "Expected EC public key for QE Identity signing certificate".to_string(),
+            ))
+        }
+    };
+
+    // Verify the QE Identity signature
+    let qe_identity_bytes = collateral.qe_identity.as_bytes();
+    let qe_identity_signature = hex::decode(&collateral.qe_identity_signature)
+        .map_err(|e| Error::InvalidSignature(format!("Failed to decode QE Identity signature: {}", e)))?;
+
+    let peer_public_key =
+        signature::UnparsedPublicKey::new(&signature::ECDSA_P256_SHA256_ASN1, ec_point);
+
+    peer_public_key
+        .verify(qe_identity_bytes, &qe_identity_signature)
+        .map_err(|_| {
+            Error::SignatureVerificationFailed(
+                "QE Identity signature verification failed".to_string(),
+            )
+        })?;
+
+    Ok(())
+}
