+    const forbidden = [
+        'process', 'require', 'child_process', 'execSync', 'exec',
+        'spawn', 'spawnSync', 'execFile', 'execFileSync', 'fork'
+    ];
+
+    // Build a function that shadows dangerous globals with undefined
+    const shadowedVars = forbidden.map(v => `${v} = undefined`).join(', ');
+    const wrappedScript = `"use strict"; var ${shadowedVars}; return (function() { ${script} }).call(this);`;
+
+    try {
+        const func = new Function(wrappedScript);
+        return func.call(context);
+    } catch (e) {
