+// Detect potentially unsafe regex patterns that could cause catastrophic backtracking
+export function isSafePattern(pattern: string): boolean {
+  try {
+    // Check for nested quantifiers which are the primary cause of ReDoS
+    // Patterns like (a+)+ or (a|a)* or (a*)*
+    // This is a simplified check that catches the most common ReDoS patterns
+
+    // Reject patterns with nested quantifiers
+    let depth = 0
+    let hasQuantifierInGroup = false
+    for (let i = 0; i < pattern.length; i++) {
+      const c = pattern[i]
+      if (c === "\\") {
+        i++ // skip escaped char
+        continue
+      }
+      if (c === "(") {
+        if (hasQuantifierInGroup) return false
+        depth++
+        hasQuantifierInGroup = false
+      } else if (c === ")") {
+        if (depth > 0) depth--
+        // Check if the group itself is followed by a quantifier - checked after
+      } else if (c === "*" || c === "+" || c === "?") {
+        if (depth > 0) hasQuantifierInGroup = true
+      } else if (c === "{") {
+        if (depth > 0) hasQuantifierInGroup = true
+      }
+    }
+    return true
+  } catch (e) {
+    return false
+  }
+}

